svg.script:
((svgElement) => {
            const width = 80;
            const height = 22;
            const chars = ".,-~:;=!*#$@";
            const textNodes = [];

            // Очищаем SVG (фон теперь прозрачный по умолчанию)
            svgElement.innerHTML = '';

            // Создаем сетку текстовых узлов
            for (let i = 0; i < width * height; i++) {
                const t = document.createElementNS("http://www.w3.org/2000/svg", "text");
                t.setAttribute("x", (i % width) * 7.5 + 5);
                t.setAttribute("y", Math.floor(i / width) * 15 + 15);
                t.setAttribute("fill", "#ccc");
                t.setAttribute("font-size", "12");
                t.setAttribute("font-family", "monospace");
                t.textContent = " ";
                svgElement.appendChild(t);
                textNodes.push(t);
            }

            let A = 0, B = 0;
            const label = " OstinUA ";

            const frame = () => {
                const b = Array(width * height).fill(" ");
                const z = Array(width * height).fill(0);

                // Математика бублика
                for (let j = 0; j < 6.28; j += 0.07) {
                    for (let i = 0; i < 6.28; i += 0.02) {
                        let c = Math.sin(i), d = Math.cos(j), e = Math.sin(A), f = Math.sin(j), g = Math.cos(A),
                            h = d + 2, D = 1 / (c * h * e + f * g + 5), l = Math.cos(i), m = Math.cos(B),
                            n = Math.sin(B), t = c * h * g - f * e;
                        let x = Math.floor(40 + 30 * D * (l * h * m - t * n));
                        let y = Math.floor(12 + 15 * D * (l * h * n + t * m));
                        let o = x + 80 * y;
                        let N = Math.floor(8 * ((f * e - c * d * g) * m - c * d * e - f * g - l * d * n));
                        if (y < 22 && y >= 0 && x < 80 && x >= 0 && D > z[o]) {
                            z[o] = D;
                            b[o] = chars[N > 0 ? N : 0];
                        }
                    }
                }

                // Позиционируем плавающую надпись OstinUA
                let labelX = Math.floor(30 + 3 * Math.cos(B));
                let labelY = Math.floor(19 + 1 * Math.sin(A));
                for(let k = 0; k < label.length; k++) {
                    let idx = (labelX + k - 4) + 80 * labelY;
                    if (idx >= 0 && idx < b.length) b[idx] = label[k];
                }

                // Обновляем символы в SVG
                for (let i = 0; i < textNodes.length; i++) {
                    if (textNodes[i].textContent !== b[i]) {
                        textNodes[i].textContent = b[i];
                        // Подсветка ника OstinUA
                        textNodes[i].setAttribute("fill", label.includes(b[i]) && b[i] !== " " ? "#0ff" : "#ccc");
                        // Прозрачность для пустых мест
                        textNodes[i].setAttribute("opacity", b[i] === " " ? "0" : "1");
                    }
                }
                A += 0.011; B += 0.011;
                requestAnimationFrame(frame);
            };
            frame();
        })(document.querySelector('svg'))
